package org.example.cpm.ir;
import java.util.*; import org.example.cpm.diagnostics.*;
public final class ModelIrValidator { public DiagnosticBag validate(ModelIR m){var b=new DiagnosticBag();var ids=new HashSet<BoneId>();for(var bone:m.bones()){if(!ids.add(bone.id()))b=b.add(Diagnostic.of(Severity.ERROR,"IR_DUPLICATE_BONE_ID","duplicate bone id"));}var set=Set.copyOf(ids);for(var root:m.roots())if(!set.contains(root))b=b.add(Diagnostic.of(Severity.ERROR,"IR_ROOT_MISSING","root not found"));for(var bone:m.bones()){if(bone.parent()!=null&&!set.contains(bone.parent()))b=b.add(Diagnostic.of(Severity.ERROR,"IR_PARENT_MISSING","parent not found"));for(var c:bone.children())if(!set.contains(c))b=b.add(Diagnostic.of(Severity.ERROR,"IR_CHILD_MISSING","child not found"));for(var cube:bone.cubes())if(!set.contains(cube.bone()))b=b.add(Diagnostic.of(Severity.ERROR,"IR_CUBE_BONE_MISSING","cube bone not found"));}for(var clip:m.clips())for(var t:clip.tracks())if(!set.contains(t.bone()))b=b.add(Diagnostic.of(Severity.ERROR,"IR_TRACK_BONE_MISSING","track bone not found"));return b;} }
